#nullable enable // autogenerated

using System.Linq;
using MVZ2.Metas;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using MVZ2Logic.Saves;
using PVZEngine;
using UnityEngine;

namespace MVZ2.Managers
{
    public partial class ResourceManager : MonoBehaviour
    {
        public StatMetaList? GetStatMetaList(string spaceName)
        {
            var modResource = GetModResource(spaceName);
            if (modResource == null)
                return null;
            return modResource.StatMetaList;
        }
        public StatCategoryMeta? GetStatCategoryMeta(NamespaceID categoryID)
        {
            if (categoryID == null)
                return null;
            var stageMetalist = GetStatMetaList(categoryID.SpaceName);
            if (stageMetalist == null)
                return null;
            return stageMetalist.categories.FirstOrDefault(m => m.ID == categoryID.Path);
        }
        public string GetStatEntryName(NamespaceID entryID, StatCategoryType type)
        {
            switch (type)
            {
                case StatCategoryType.Entity:
                    return GetEntityName(entryID);
                case StatCategoryType.Stage:
                    return Main.LevelManager.GetStageName(entryID);
            }
            return entryID.ToString();
        }
        public StatEntryMeta? GetStatDirectEntryMeta(NamespaceID entryID)
        {
            if (!NamespaceID.IsValid(entryID))
                return null;
            var stageMetalist = GetStatMetaList(entryID.SpaceName);
            if (stageMetalist == null)
                return null;
            return stageMetalist.entries.FirstOrDefault(m => m.ID == entryID.Path);
        }
        public bool ShouldStatEntryDisplay(NamespaceID entryID, StatCategoryType type)
        {
            switch (type)
            {
                case StatCategoryType.Entity:
                    {
                        var entityDef = Main.Game.GetEntityDefinition(entryID);
                        if (entityDef == null)
                            return false;
                        if (entityDef.HideInStats())
                            return false;
                        return true;
                    }
                case StatCategoryType.Stage:
                    {
                        var stageDef = Main.Game.GetStageDefinition(entryID);
                        if (stageDef == null)
                            return false;
                        if (stageDef.HideInStats())
                            return false;
                        return true;
                    }
            }
            return false;
        }
    }
}
